import static java.lang.System.out;
public class Main {
	private static int capacity = 10;
	private static String[] items = new String[] { "a", "b", "c", "d", "e" };
	private static int[] weight = new int[] { 2, 2, 6, 5, 4 };
	private static int[] value = new int[] { 6, 3, 5, 4, 6 };
