```java 二分查找
/**
 * Arrays.binarySearch()
 */
int binarySearch(int[] array, int x) {
    int low = 0;
    int high = array.length - 1;
    int middle;
    while (low <= high) {
        middle = (low + high) / 2;
        if (array[middle] == x) {
            return middle;
        } else if (array[middle] < x) {
            low = middle + 1;
        } else {
            high = middle - 1;
        }
    }
    return -1;
}
