/**
 * 输出的序列无顺序
 * 思想：冒泡排序，不断和后面的交换
 */
static void permutate(char[] array, int from, int to) {
    if (from == to) { // 输出
        System.out.println(new String(array));
    } else {
        for (int i = from; i < to; i++) {
            if (isUnique(array, from, i)) { // 去重
                swap(array, from, i); // 交换元素
                permutate(array, from + 1, to); // 交换后，再进行全排列算法
                swap(array, from, i); // 还原成原来的数组，便于下一次的全排列
            }
        }
    }
}

static boolean isUnique(char[] array, int begin, int end) {
    for (int i = begin; i < end; i++)
        if (array[i] == array[end])
            return false;
    return true;
}

static void swap(char[] array, int m, int n) {
    char tmp = array[n];
    array[n] = array[m];
    array[m] = tmp;
}
