		for (int i = 1; i < 999999; i++) {
			if (sumEach(i)) {
				num++;
			}
		}
		System.out.println(num);
	}

	private static boolean sumEach(int n) {
		int sum = 0;
		int cube = n * n * n;
		while (cube > 0) {
			sum += cube % 10;
			cube /= 10;
		}
		return sum == n;
	}
}
