import java.util.Scanner;
public class Main {
	public static void main(String[] args) {
		Scanner scanner = new Scanner(System.in);
		int n = scanner.nextInt();
		scanner.close();
		int sum = n;
		// n瓶饮料，n个瓶盖，可以换n/3瓶饮料
		int nTrade = n / 3;
		// 换了后，剩余的饮料
		int rest = n - nTrade * 3;
		// 换来的饮料和剩余饮料的瓶盖，又可以换n/3瓶饮料
		int againTrade = (nTrade + rest) / 3;
