import java.util.HashMap;
import java.util.Map;

public class Main {
	public static void main(String[] args) {
		Map<Integer, Boolean> isPut = new HashMap<>();
		int a = 2;
		int sum = 0;
		while (true) {
			while (a != 0) {
				sum += Math.pow(a % 10, 2);
				a /= 10;
			}
			a = sum;
			sum = 0;
			// 落入循环即以前已经添加过
			if (isPut.get(a) != null) {
