```java 日期检查
try {
	Calendar calendar = Calendar.getInstance();
	// 取消宽松，不然日期出错会跳到下一天
	calendar.setLenient(false);
	// 中间的month从0开始，而1表示2月
	calendar.set(2017, 1, 29);
